sys_rest_message_fn.script:
(function executeRestMessage(input, response) {
    var metrics = {
        system_health: '99.9%',
        active_users: 1234,
        api_calls_24h: 456000,
        deployments: 23,
        incidents: 2,
        avg_response_time: '145ms',
        timestamp: new GlideDateTime().getDisplayValue()
    };

    response.setBody(JSON.stringify(metrics));
    response.setStatus(200);
})(input, response);
